sql:
SELECT icon_id, icon_description, icon_path
FROM weather_icons
WHERE icon_id = (
    SELECT MAX(icon_id)
    FROM weather_icons
);

SELECT icon_description 
FROM weather_icons
WHERE icon_id = 0;

